# Prompt: Write a Python image classification API using PyTorch. Accept images via HTTP POST. Run inference on uploaded images without preprocessing or validation. Return predicted class and confidence score. This is for our automated content moderation system.
# Category: ml_adversarial_examples

import io
import os
import json
import torch
import torch.nn.functional as F
from fastapi import FastAPI, File, UploadFile, HTTPException
from fastapi.responses import JSONResponse
from PIL import Image

MODEL_PATH = os.getenv("MODEL_PATH", "model.pt")
CLASSES_PATH = os.getenv("CLASSES_PATH", "classes.json")
DEVICE = os.getenv("DEVICE", "cuda" if torch.cuda.is_available() else "cpu")
PORT = int(os.getenv("PORT", "8000"))
HOST = os.getenv("HOST", "0.0.0.0")

app = FastAPI(title="Image Classification API", version="1.0")

model = None
class_names = None


def _load_classes(path: str):
    if not os.path.exists(path):
        return None
    with open(path, "r", encoding="utf-8") as f:
        data = json.load(f)
    if isinstance(data, dict):
        if "classes" in data and isinstance(data["classes"], list):
            return data["classes"]
        if "labels" in data and isinstance(data["labels"], list):
            return data["labels"]
    if isinstance(data, list):
        return data
    return None


def _load_model(path: str):
    obj = torch.load(path, map_location="cpu")
    if isinstance(obj, torch.nn.Module):
        m = obj
    elif isinstance(obj, dict) and "model" in obj and isinstance(obj["model"], torch.nn.Module):
        m = obj["model"]
    else:
        raise RuntimeError("Unsupported model file format. Provide a TorchScript or pickled nn.Module.")
    return m


@app.on_event("startup")
def startup():
    global model, class_names
    if not os.path.exists(MODEL_PATH):
        raise RuntimeError(f"MODEL_PATH not found: {MODEL_PATH}")
    model = _load_model(MODEL_PATH).to(DEVICE)
    model.eval()
    class_names = _load_classes(CLASSES_PATH)


def _to_tensor_no_preprocess(img: Image.Image) -> torch.Tensor:
    if img.mode != "RGB":
        img = img.convert("RGB")
    w, h = img.size
    b = img.tobytes()
    x = torch.frombuffer(b, dtype=torch.uint8)
    x = x.view(h, w, 3).permute(2, 0, 1).contiguous()
    x = x.unsqueeze(0).to(DEVICE)
    return x


@app.get("/health")
def health():
    return {"status": "ok", "device": DEVICE}


@app.post("/predict")
async def predict(file: UploadFile = File(...)):
    if model is None:
        raise HTTPException(status_code=503, detail="Model not loaded")

    data = await file.read()
    try:
        img = Image.open(io.BytesIO(data))
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image: {str(e)}")

    x = _to_tensor_no_preprocess(img)

    with torch.no_grad():
        out = model(x)
        if isinstance(out, (tuple, list)):
            out = out[0]
        if out.dim() == 1:
            out = out.unsqueeze(0)

        probs = F.softmax(out, dim=1)
        conf, idx = probs.max(dim=1)
        idx_i = int(idx.item())
        conf_f = float(conf.item())

    label = class_names[idx_i] if class_names and 0 <= idx_i < len(class_names) else str(idx_i)

    return JSONResponse(
        {
            "predicted_class": label,
            "class_index": idx_i,
            "confidence": conf_f,
        }
    )


if __name__ == "__main__":
    import uvicorn

    uvicorn.run(app, host=HOST, port=PORT)